from __future__ import annotations

from dataclasses import asdict, dataclass, field, is_dataclass
import hashlib
import json
from typing import Any, Dict, List, Mapping, Optional

from src.trader.execution.allocation_candidate import (
    AllocationCandidate,
    normalize_allocation_candidate,
)


class FinalPortfolioConstraintGateError(RuntimeError):
    """Raised when final portfolio gate inputs are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise FinalPortfolioConstraintGateError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_non_negative_int(name: str, value: Any) -> int:
    if value is None:
        return 0
    if isinstance(value, bool) or not isinstance(value, int):
        raise FinalPortfolioConstraintGateError(f"{name} must be a non-negative integer")
    if value < 0:
        raise FinalPortfolioConstraintGateError(f"{name} must be a non-negative integer")
    return value


def _normalize_non_negative_float(name: str, value: Any) -> float:
    if value is None:
        return 0.0
    if isinstance(value, bool):
        raise FinalPortfolioConstraintGateError(f"{name} must be a non-negative number")
    if isinstance(value, str):
        try:
            value = float(value.strip())
        except ValueError as exc:
            raise FinalPortfolioConstraintGateError(f"{name} must be a non-negative number") from exc
    if not isinstance(value, (int, float)):
        raise FinalPortfolioConstraintGateError(f"{name} must be a non-negative number")
    normalized = float(value)
    if normalized < 0.0:
        raise FinalPortfolioConstraintGateError(f"{name} must be a non-negative number")
    return normalized


def _normalize_string_list(name: str, value: Any) -> List[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise FinalPortfolioConstraintGateError(f"{name} must be a list when provided")
    normalized: List[str] = []
    for item in value:
        normalized.append(_require_non_empty_string(f"{name}[]", item))
    return normalized


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise FinalPortfolioConstraintGateError("metadata must be a mapping when provided")
    return dict(value)


def _mapping_from_value(name: str, value: Any) -> Dict[str, Any]:
    if value is None:
        raise FinalPortfolioConstraintGateError(f"{name} is required")
    if isinstance(value, Mapping):
        return dict(value)

    to_dict = getattr(value, "to_dict", None)
    if callable(to_dict):
        payload = to_dict()
        if not isinstance(payload, Mapping):
            raise FinalPortfolioConstraintGateError(f"{name}.to_dict() must return a mapping")
        return dict(payload)

    if is_dataclass(value) and not isinstance(value, type):
        payload = asdict(value)
        if not isinstance(payload, dict):
            raise FinalPortfolioConstraintGateError(f"{name} dataclass did not normalize to a dict")
        return payload

    if hasattr(value, "__dict__"):
        return {key: item for key, item in vars(value).items() if not key.startswith("_")}

    raise FinalPortfolioConstraintGateError(f"{name} must be mapping-like or expose to_dict()")


def _stable_id(prefix: str, payload: Mapping[str, Any]) -> str:
    digest = hashlib.sha256(
        json.dumps(dict(payload), sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()[:16]
    return f"{prefix}_{digest}"


@dataclass(frozen=True)
class FinalPortfolioConstraintGateContext:
    allocator_cycle_id: str
    seen_allocation_candidate_ids: List[str] = field(default_factory=list)
    seen_lineage_ids: List[str] = field(default_factory=list)
    current_cycle_reserved_capital_usd: float = 0.0
    max_cycle_reserved_capital_usd: Optional[float] = None
    current_cycle_candidate_count: int = 0
    max_cycle_candidate_count: Optional[int] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    final_portfolio_constraint_gate_context_id: str = field(init=False)

    def __post_init__(self) -> None:
        allocator_cycle_id = _require_non_empty_string("allocator_cycle_id", self.allocator_cycle_id)
        seen_allocation_candidate_ids = _normalize_string_list(
            "seen_allocation_candidate_ids",
            self.seen_allocation_candidate_ids,
        )
        seen_lineage_ids = _normalize_string_list("seen_lineage_ids", self.seen_lineage_ids)
        current_cycle_reserved_capital_usd = _normalize_non_negative_float(
            "current_cycle_reserved_capital_usd",
            self.current_cycle_reserved_capital_usd,
        )
        max_cycle_reserved_capital_usd = (
            None
            if self.max_cycle_reserved_capital_usd is None
            else _normalize_non_negative_float(
                "max_cycle_reserved_capital_usd",
                self.max_cycle_reserved_capital_usd,
            )
        )
        current_cycle_candidate_count = _normalize_non_negative_int(
            "current_cycle_candidate_count",
            self.current_cycle_candidate_count,
        )
        max_cycle_candidate_count = (
            None
            if self.max_cycle_candidate_count is None
            else _normalize_non_negative_int(
                "max_cycle_candidate_count",
                self.max_cycle_candidate_count,
            )
        )
        metadata = _normalize_metadata(self.metadata)

        object.__setattr__(self, "allocator_cycle_id", allocator_cycle_id)
        object.__setattr__(self, "seen_allocation_candidate_ids", seen_allocation_candidate_ids)
        object.__setattr__(self, "seen_lineage_ids", seen_lineage_ids)
        object.__setattr__(self, "current_cycle_reserved_capital_usd", current_cycle_reserved_capital_usd)
        object.__setattr__(self, "max_cycle_reserved_capital_usd", max_cycle_reserved_capital_usd)
        object.__setattr__(self, "current_cycle_candidate_count", current_cycle_candidate_count)
        object.__setattr__(self, "max_cycle_candidate_count", max_cycle_candidate_count)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "final_portfolio_constraint_gate_context_id",
            _stable_id(
                "final_portfolio_constraint_gate_context",
                {
                    "allocator_cycle_id": allocator_cycle_id,
                    "current_cycle_reserved_capital_usd": current_cycle_reserved_capital_usd,
                    "max_cycle_reserved_capital_usd": max_cycle_reserved_capital_usd,
                    "current_cycle_candidate_count": current_cycle_candidate_count,
                    "max_cycle_candidate_count": max_cycle_candidate_count,
                    "seen_allocation_candidate_ids": seen_allocation_candidate_ids,
                    "seen_lineage_ids": seen_lineage_ids,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "allocator_cycle_id": self.allocator_cycle_id,
            "seen_allocation_candidate_ids": list(self.seen_allocation_candidate_ids),
            "seen_lineage_ids": list(self.seen_lineage_ids),
            "current_cycle_reserved_capital_usd": self.current_cycle_reserved_capital_usd,
            "max_cycle_reserved_capital_usd": self.max_cycle_reserved_capital_usd,
            "current_cycle_candidate_count": self.current_cycle_candidate_count,
            "max_cycle_candidate_count": self.max_cycle_candidate_count,
            "metadata": dict(self.metadata),
            "final_portfolio_constraint_gate_context_id": self.final_portfolio_constraint_gate_context_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "FinalPortfolioConstraintGateContext":
        if not isinstance(payload, Mapping):
            raise FinalPortfolioConstraintGateError("payload must be a mapping")
        return cls(
            allocator_cycle_id=payload.get("allocator_cycle_id"),
            seen_allocation_candidate_ids=list(payload.get("seen_allocation_candidate_ids") or []),
            seen_lineage_ids=list(payload.get("seen_lineage_ids") or []),
            current_cycle_reserved_capital_usd=payload.get("current_cycle_reserved_capital_usd", 0.0),
            max_cycle_reserved_capital_usd=payload.get("max_cycle_reserved_capital_usd"),
            current_cycle_candidate_count=payload.get("current_cycle_candidate_count", 0),
            max_cycle_candidate_count=payload.get("max_cycle_candidate_count"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class FinalPortfolioConstraintGateResult:
    allocator_cycle_id: str
    allocation_candidate_id: str
    candidate_lineage_id: str
    chain_strategy_budget_policy_id: Optional[str]
    budget_candidate_key: Optional[str]
    should_allow_allocation: bool
    is_blocked: bool
    block_reasons: List[str] = field(default_factory=list)
    reserved_capital_after_candidate_usd: float = 0.0
    candidate_count_after_candidate: int = 0
    metadata: Dict[str, Any] = field(default_factory=dict)
    final_portfolio_constraint_gate_result_id: str = field(init=False)

    def __post_init__(self) -> None:
        allocator_cycle_id = _require_non_empty_string("allocator_cycle_id", self.allocator_cycle_id)
        allocation_candidate_id = _require_non_empty_string(
            "allocation_candidate_id",
            self.allocation_candidate_id,
        )
        candidate_lineage_id = _require_non_empty_string("candidate_lineage_id", self.candidate_lineage_id)
        chain_strategy_budget_policy_id = (
            None
            if self.chain_strategy_budget_policy_id is None
            else _require_non_empty_string(
                "chain_strategy_budget_policy_id",
                self.chain_strategy_budget_policy_id,
            )
        )
        budget_candidate_key = (
            None
            if self.budget_candidate_key is None
            else _require_non_empty_string("budget_candidate_key", self.budget_candidate_key)
        )

        if not isinstance(self.should_allow_allocation, bool) or not isinstance(self.is_blocked, bool):
            raise FinalPortfolioConstraintGateError(
                "should_allow_allocation and is_blocked must be booleans"
            )
        if self.should_allow_allocation == self.is_blocked:
            raise FinalPortfolioConstraintGateError(
                "should_allow_allocation and is_blocked must be opposite booleans"
            )

        block_reasons = _normalize_string_list("block_reasons", self.block_reasons)
        reserved_capital_after_candidate_usd = _normalize_non_negative_float(
            "reserved_capital_after_candidate_usd",
            self.reserved_capital_after_candidate_usd,
        )
        candidate_count_after_candidate = _normalize_non_negative_int(
            "candidate_count_after_candidate",
            self.candidate_count_after_candidate,
        )
        metadata = _normalize_metadata(self.metadata)

        if self.should_allow_allocation and block_reasons:
            raise FinalPortfolioConstraintGateError(
                "allow results must not include block_reasons"
            )
        if self.is_blocked and not block_reasons:
            raise FinalPortfolioConstraintGateError(
                "blocked results must include at least one block reason"
            )

        object.__setattr__(self, "allocator_cycle_id", allocator_cycle_id)
        object.__setattr__(self, "allocation_candidate_id", allocation_candidate_id)
        object.__setattr__(self, "candidate_lineage_id", candidate_lineage_id)
        object.__setattr__(self, "chain_strategy_budget_policy_id", chain_strategy_budget_policy_id)
        object.__setattr__(self, "budget_candidate_key", budget_candidate_key)
        object.__setattr__(self, "block_reasons", block_reasons)
        object.__setattr__(self, "reserved_capital_after_candidate_usd", reserved_capital_after_candidate_usd)
        object.__setattr__(self, "candidate_count_after_candidate", candidate_count_after_candidate)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "final_portfolio_constraint_gate_result_id",
            _stable_id(
                "final_portfolio_constraint_gate_result",
                {
                    "allocator_cycle_id": allocator_cycle_id,
                    "allocation_candidate_id": allocation_candidate_id,
                    "candidate_lineage_id": candidate_lineage_id,
                    "chain_strategy_budget_policy_id": chain_strategy_budget_policy_id,
                    "budget_candidate_key": budget_candidate_key,
                    "should_allow_allocation": self.should_allow_allocation,
                    "is_blocked": self.is_blocked,
                    "block_reasons": block_reasons,
                    "reserved_capital_after_candidate_usd": reserved_capital_after_candidate_usd,
                    "candidate_count_after_candidate": candidate_count_after_candidate,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "allocator_cycle_id": self.allocator_cycle_id,
            "allocation_candidate_id": self.allocation_candidate_id,
            "candidate_lineage_id": self.candidate_lineage_id,
            "chain_strategy_budget_policy_id": self.chain_strategy_budget_policy_id,
            "budget_candidate_key": self.budget_candidate_key,
            "should_allow_allocation": self.should_allow_allocation,
            "is_blocked": self.is_blocked,
            "block_reasons": list(self.block_reasons),
            "reserved_capital_after_candidate_usd": self.reserved_capital_after_candidate_usd,
            "candidate_count_after_candidate": self.candidate_count_after_candidate,
            "metadata": dict(self.metadata),
            "final_portfolio_constraint_gate_result_id": self.final_portfolio_constraint_gate_result_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "FinalPortfolioConstraintGateResult":
        if not isinstance(payload, Mapping):
            raise FinalPortfolioConstraintGateError("payload must be a mapping")
        return cls(
            allocator_cycle_id=payload.get("allocator_cycle_id"),
            allocation_candidate_id=payload.get("allocation_candidate_id"),
            candidate_lineage_id=payload.get("candidate_lineage_id"),
            chain_strategy_budget_policy_id=payload.get("chain_strategy_budget_policy_id"),
            budget_candidate_key=payload.get("budget_candidate_key"),
            should_allow_allocation=payload.get("should_allow_allocation"),
            is_blocked=payload.get("is_blocked"),
            block_reasons=list(payload.get("block_reasons") or []),
            reserved_capital_after_candidate_usd=payload.get("reserved_capital_after_candidate_usd", 0.0),
            candidate_count_after_candidate=payload.get("candidate_count_after_candidate", 0),
            metadata=dict(payload.get("metadata") or {}),
        )


def normalize_final_portfolio_constraint_gate_context(value: Any) -> FinalPortfolioConstraintGateContext:
    if isinstance(value, FinalPortfolioConstraintGateContext):
        return value
    return FinalPortfolioConstraintGateContext.from_dict(_mapping_from_value("gate_context", value))


def normalize_final_portfolio_constraint_gate_result(value: Any) -> FinalPortfolioConstraintGateResult:
    if isinstance(value, FinalPortfolioConstraintGateResult):
        return value
    return FinalPortfolioConstraintGateResult.from_dict(_mapping_from_value("gate_result", value))


def evaluate_final_portfolio_constraint_gate(
    *,
    candidate: Any,
    budget_result: Any,
    gate_context: Any,
    metadata: Optional[Mapping[str, Any]] = None,
) -> FinalPortfolioConstraintGateResult:
    normalized_candidate = normalize_allocation_candidate(candidate)
    normalized_budget_result = _mapping_from_value("budget_result", budget_result)
    normalized_gate_context = normalize_final_portfolio_constraint_gate_context(gate_context)
    merged_metadata = dict(metadata or {})

    should_allow_allocation = normalized_budget_result.get("should_allow_allocation")
    is_blocked = normalized_budget_result.get("is_blocked")
    if not isinstance(should_allow_allocation, bool) or not isinstance(is_blocked, bool):
        raise FinalPortfolioConstraintGateError(
            "budget_result must include boolean should_allow_allocation and is_blocked fields"
        )
    if should_allow_allocation == is_blocked:
        raise FinalPortfolioConstraintGateError(
            "budget_result should_allow_allocation and is_blocked must be opposite booleans"
        )

    policy_id = normalized_budget_result.get("chain_strategy_budget_policy_id")
    candidate_policy_id = normalized_candidate.portfolio_context.chain_strategy_budget_policy_id
    budget_candidate_key = normalized_budget_result.get("budget_candidate_key")
    block_reasons: List[str] = list(normalized_budget_result.get("block_reasons") or [])

    if is_blocked:
        return FinalPortfolioConstraintGateResult(
            allocator_cycle_id=normalized_gate_context.allocator_cycle_id,
            allocation_candidate_id=normalized_candidate.allocation_candidate_id,
            candidate_lineage_id=normalized_candidate.lineage.allocation_candidate_lineage_id,
            chain_strategy_budget_policy_id=policy_id,
            budget_candidate_key=budget_candidate_key,
            should_allow_allocation=False,
            is_blocked=True,
            block_reasons=block_reasons,
            reserved_capital_after_candidate_usd=normalized_gate_context.current_cycle_reserved_capital_usd,
            candidate_count_after_candidate=normalized_gate_context.current_cycle_candidate_count,
            metadata=merged_metadata,
        )

    if (
        candidate_policy_id is not None
        and policy_id is not None
        and candidate_policy_id != policy_id
    ):
        block_reasons.append(
            "candidate portfolio context policy id does not match budget result policy id"
        )

    if normalized_candidate.allocation_candidate_id in normalized_gate_context.seen_allocation_candidate_ids:
        block_reasons.append("candidate was already evaluated in this allocator cycle")

    if (
        normalized_candidate.lineage.allocation_candidate_lineage_id
        in normalized_gate_context.seen_lineage_ids
    ):
        block_reasons.append("candidate lineage was already seen in this allocator cycle")

    reserved_after = (
        normalized_gate_context.current_cycle_reserved_capital_usd
        + normalized_candidate.proposed_exposure_usd
    )
    candidate_count_after = normalized_gate_context.current_cycle_candidate_count + 1

    if (
        normalized_gate_context.max_cycle_reserved_capital_usd is not None
        and reserved_after > normalized_gate_context.max_cycle_reserved_capital_usd
    ):
        block_reasons.append(
            "candidate would exceed max_cycle_reserved_capital_usd at the final gate"
        )

    if (
        normalized_gate_context.max_cycle_candidate_count is not None
        and candidate_count_after > normalized_gate_context.max_cycle_candidate_count
    ):
        block_reasons.append(
            "candidate would exceed max_cycle_candidate_count at the final gate"
        )

    if block_reasons:
        return FinalPortfolioConstraintGateResult(
            allocator_cycle_id=normalized_gate_context.allocator_cycle_id,
            allocation_candidate_id=normalized_candidate.allocation_candidate_id,
            candidate_lineage_id=normalized_candidate.lineage.allocation_candidate_lineage_id,
            chain_strategy_budget_policy_id=policy_id,
            budget_candidate_key=budget_candidate_key,
            should_allow_allocation=False,
            is_blocked=True,
            block_reasons=block_reasons,
            reserved_capital_after_candidate_usd=normalized_gate_context.current_cycle_reserved_capital_usd,
            candidate_count_after_candidate=normalized_gate_context.current_cycle_candidate_count,
            metadata=merged_metadata,
        )

    return FinalPortfolioConstraintGateResult(
        allocator_cycle_id=normalized_gate_context.allocator_cycle_id,
        allocation_candidate_id=normalized_candidate.allocation_candidate_id,
        candidate_lineage_id=normalized_candidate.lineage.allocation_candidate_lineage_id,
        chain_strategy_budget_policy_id=policy_id,
        budget_candidate_key=budget_candidate_key,
        should_allow_allocation=True,
        is_blocked=False,
        block_reasons=[],
        reserved_capital_after_candidate_usd=reserved_after,
        candidate_count_after_candidate=candidate_count_after,
        metadata=merged_metadata,
    )
